func:
// 1. Defensive Coding: ตรวจสอบความถูกต้องของ Payload
if (!msg.payload) {
    node.warn("ไม่มีข้อมูล Payload จาก Windows SNMP");
    return null;
}

if (msg.payload.error) {
    node.error("SNMP Windows Error: " + msg.payload.error);
    return null;
}

// 2. แปลงเป็น Array เสมอ
let data = Array.isArray(msg.payload) ? msg.payload : [msg.payload];

// 3. ตรวจสอบว่าได้ข้อมูลครบ 5 ตัวตาม OID หรือไม่
if (data.length < 5) {
    node.warn("⚠️ ข้อมูล Windows มาไม่ครบ 5 ตัว ได้มาแค่: " + data.length + " ตัว");
    return null;
}

try {
    // 4. ดึงข้อมูลทีละตัว (ป้องกันค่า undefined ด้วย || 0)
    let cpuLoad    = parseFloat(data[0].value || 0);
    let ramTotalKB = parseFloat(data[1].value || 0);
    let ramUsedKB  = parseFloat(data[2].value || 0);
    let diskTotalKB= parseFloat(data[3].value || 0);
    let diskUsedKB = parseFloat(data[4].value || 0);

    // 5. คำนวณหน่วย RAM (KB -> MB)
    let ramTotalMB = (ramTotalKB / 1024).toFixed(2);
    let ramUsedMB  = (ramUsedKB / 1024).toFixed(2);
    let ramFreeMB  = (parseFloat(ramTotalMB) - parseFloat(ramUsedMB)).toFixed(2);

    // 6. คำนวณหน่วย Disk (KB -> GB)
    let diskTotalGB = (diskTotalKB / 1048576).toFixed(2);
    let diskUsedGB  = (diskUsedKB / 1048576).toFixed(2);
    let diskFreeGB  = (parseFloat(diskTotalGB) - parseFloat(diskUsedGB)).toFixed(2);

    // 7. จัดรูปแบบ JSON Output ให้สวยงาม
    msg.payload = {
        machine_id: "ERP-Windows-Simulator",
        cpu_load_percent: cpuLoad,
        memory: {
            total_mb: parseFloat(ramTotalMB),
            used_mb: parseFloat(ramUsedMB),
            free_mb: parseFloat(ramFreeMB)
        },
        disk: {
            total_gb: parseFloat(diskTotalGB),
            used_gb: parseFloat(diskUsedGB),
            free_gb: parseFloat(diskFreeGB)
        },
        timestamp: new Date().toISOString()
    };

    // --- ส่วนนี้เตรียมไว้สำหรับเสียบเข้าโหนด PostgreSQL ---
    msg.query = "INSERT INTO ims.machine_telemetry (time, machine_id, cpu_load, ram_used_mb, disk_used_gb) VALUES (NOW(), $1, $2, $3, $4);";
    msg.params = [
        msg.payload.machine_id,
        msg.payload.cpu_load_percent,
        msg.payload.memory.used_mb,
        msg.payload.disk.used_gb
    ];

    return msg;

} catch (error) {
    node.error("💥 พังตอนแปลงข้อมูล Windows: " + error.message);
    return null;
}

if (!msg.payload) { return null; }
if (msg.payload.error) { return null; }

let data = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
if (data.length < 5) { return null; }

try {
    let cpuLoad    = parseFloat(data[0].value || 0);
    let ramTotalKB = parseFloat(data[1].value || 0);
    let ramUsedKB  = parseFloat(data[2].value || 0);
    let diskTotalKB= parseFloat(data[3].value || 0);
    let diskUsedKB = parseFloat(data[4].value || 0);

    let ramTotalMB = (ramTotalKB / 1024).toFixed(2);
    let ramUsedMB  = (ramUsedKB / 1024).toFixed(2);
    let ramFreeMB  = (parseFloat(ramTotalMB) - parseFloat(ramUsedMB)).toFixed(2);

    let diskTotalGB = (diskTotalKB / 1048576).toFixed(2);
    let diskUsedGB  = (diskUsedKB / 1048576).toFixed(2);
    let diskFreeGB  = (parseFloat(diskTotalGB) - parseFloat(diskUsedGB)).toFixed(2);

    msg.payload = {
        machine_id: "Windows-Simulator",
        cpu_load_percent: cpuLoad,
        ram_total_mb: parseFloat(ramTotalMB),
        ram_used_mb: parseFloat(ramUsedMB),
        ram_free_mb: parseFloat(ramFreeMB),
        disk_total_gb: parseFloat(diskTotalGB),
        disk_used_gb: parseFloat(diskUsedGB),
        disk_free_gb: parseFloat(diskFreeGB),
        timestamp: new Date().toISOString()
    };

    return msg;
} catch (error) {
    return null;
}

if (!msg.payload) { return null; }
if (msg.payload.error) {
    node.error("Ubuntu SNMP Error: " + msg.payload.error);
    return null;
}

let data = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
if (data.length < 3) { return null; }

try {
    let cpuLoad = parseFloat(data[0].value || 0);
    let ramTotalKB = parseFloat(data[1].value || 0);
    let ramFreeKB = parseFloat(data[2].value || 0);

    let ramTotalMB = (ramTotalKB / 1024).toFixed(2);
    let ramFreeMB = (ramFreeKB / 1024).toFixed(2);
    let ramUsedMB = (parseFloat(ramTotalMB) - parseFloat(ramFreeMB)).toFixed(2);

    msg.payload = {
        machine_id: "Ubuntu-ERP-MASTER",
        cpu_load_1m: cpuLoad,
        ram_total_mb: parseFloat(ramTotalMB),
        ram_used_mb: parseFloat(ramUsedMB),
        ram_free_mb: parseFloat(ramFreeMB),
        timestamp: new Date().toISOString()
    };

    return msg;
} catch (error) {
    node.error("Parse Error Ubuntu: " + error.message);
    return null;
}

const varbinds = msg.payload;
if (!Array.isArray(varbinds) || varbinds.length === 0) { return null; }

const disks = {};
varbinds.forEach(item => {
    const match = item.oid.match(/\.(\d+)$/);
    if (!match) return;
    const index = match[1];
    if (!disks[index]) disks[index] = {};

    if (item.oid.startsWith("1.3.6.1.2.1.25.2.3.1.3.")) disks[index].descr = Buffer.isBuffer(item.value) ? item.value.toString('ascii') : item.value;
    if (item.oid.startsWith("1.3.6.1.2.1.25.2.3.1.4.")) disks[index].allocUnit = Number(item.value);
    if (item.oid.startsWith("1.3.6.1.2.1.25.2.3.1.5.")) disks[index].sizeBlocks = Number(item.value);
    if (item.oid.startsWith("1.3.6.1.2.1.25.2.3.1.6.")) disks[index].usedBlocks = Number(item.value);
});

let summary = { total_GB: 0, used_GB: 0, free_GB: 0 };
for (const index in disks) {
    const d = disks[index];
    if (d.descr && d.sizeBlocks > 0 && d.allocUnit > 0) {
        // Filter out RAM and Docker overlays
        if (d.descr.toUpperCase().includes("MEMORY") || d.descr.includes("run/containerd")) continue;

        const totalBytes = d.sizeBlocks * d.allocUnit;
        const usedBytes = d.usedBlocks * d.allocUnit;
        summary.total_GB += totalBytes / 1024**3;
        summary.used_GB += usedBytes / 1024**3;
        summary.free_GB += (totalBytes - usedBytes) / 1024**3;
    }
}

msg.payload = {
    machine_id: "Ubuntu-ERP-MASTER",
    disk_total_gb: Number(summary.total_GB.toFixed(2)),
    disk_used_gb: Number(summary.used_GB.toFixed(2)),
    disk_free_gb: Number(summary.free_GB.toFixed(2)),
    timestamp: new Date().toISOString()
};

return msg;
